class UserRegistrationSystem:
    """Handles user registration, authentication, and profile management."""

    def __init__(self):
        self.users: dict = {}
        self.sessions: dict = {}
        self.email_index: dict = {}
        self.username_index: dict = {}

    def _hash_password(self, password: str, salt: str = None) -> tuple:
        if salt is None:
            salt = os.urandom(16).hex()
        hashed = hashlib.pbkdf2_hmac(
            'sha256', password.encode(), salt.encode(), 100000
        ).hex()
        return f"{salt}:{hashed}", salt

    def _verify_password(self, password: str, stored_hash: str) -> bool:
        salt, expected_hash = stored_hash.split(':')
        actual_hash, _ = self._hash_password(password, salt)
        return actual_hash == stored_hash

    def register_user(self, username: str, email: str, password: str,
                      display_name: str = "") -> dict:
        if email in self.email_index:
            return {"success": False, "error": "Email already registered"}
        if username in self.username_index:
            return {"success": False, "error": "Username already taken"}
        if len(password) < 8:
            return {"success": False, "error": "Password must be at least 8 characters"}

        user_id = str(uuid.uuid4())
        password_hash, _ = self._hash_password(password)

        profile = UserProfile(
            user_id=user_id,
            username=username,
            email=email,
            password_hash=password_hash,
            display_name=display_name or username
        )

        self.users[user_id] = profile
        self.email_index[email] = user_id
        self.username_index[username] = user_id

        return {"success": True, "user_id": user_id, "message": "Registration successful"}

    def authenticate(self, email: str, password: str) -> dict:
        if email not in self.email_index:
            return {"success": False, "error": "Invalid credentials"}

        user_id = self.email_index[email]
        user = self.users[user_id]

        if not self._verify_password(password, user.password_hash):
            return {"success": False, "error": "Invalid credentials"}

        if not user.is_active:
            return {"success": False, "error": "Account is deactivated"}

        session_token = str(uuid.uuid4())
        self.sessions[session_token] = {
            "user_id": user_id,
            "created_at": datetime.utcnow().isoformat(),
            "expires_at": (datetime.utcnow() + timedelta(hours=24)).isoformat()
        }

        return {"success": True, "session_token": session_token, "user_id": user_id}

    def get_user(self, user_id: str) -> Optional[UserProfile]:
        return self.users.get(user_id)

    def update_profile(self, user_id: str, **kwargs) -> dict:
        if user_id not in self.users:
            return {"success": False, "error": "User not found"}

        user = self.users[user_id]
        allowed_fields = [
            'display_name', 'bio', 'interests', 'profile_picture', 'cultural_background'
        ]

        for key, value in kwargs.items():
            if key in allowed_fields:
                setattr(user, key, value)

        return {"success": True, "message": "Profile updated"}

    def upload_profile_picture(self, user_id: str, file_path: str) -> dict:
        if user_id not in self.users:
            return {"success": False, "error": "User not found"}

        allowed_extensions = ['.jpg', '.jpeg', '.png', '.gif', '.webp']
        ext = os.path.splitext(file_path)[1].lower()
        if ext not in allowed_extensions:
            return {"success": False, "error": "Invalid file format"}

        stored_path = f"/uploads/profiles/{user_id}{ext}"
        self.users[user_id].profile_picture = stored_path

        return {"success": True, "path": stored_path}

    def set_cultural_background(self, user_id: str, country: str,
                                region: str = "", languages: list = None,
                                traditions: list = None, cuisine: list = None,
                                arts: list = None, description: str = "") -> dict:
        if user_id not in self.users:
            return {"success": False, "error": "User not found"}

        background = CulturalBackground(
            country=country,
            region=region,
            languages=languages or [],
            traditions=traditions or [],
            cuisine=cuisine or [],
            arts=arts or [],
            description=description
        )
        self.users[user_id].cultural_background = background

        return {"success": True, "message": "Cultural background updated"}

    def search_users(self, query: str = "", country: str = "",
                     language: str = "", interest: str = "") -> list:
        results = []
        for user in self.users.values():
            if not user.is_active:
                continue
            if query and query.lower() not in user.display_name.lower():
                continue
            if country and user.cultural_background:
                if country.lower() != user.cultural_background.country.lower():
                    continue
            if language and user.cultural_background:
                langs = [l.lower() for l in user.cultural_background.languages]
                if language.lower() not in langs:
                    continue
            if interest:
                interests_lower = [i.lower() for i in user.interests]
                if interest.lower() not in interests_lower:
                    continue
            results.append(user)
        return results

    def deactivate_account(self, user_id: str) -> dict:
        if user_id not in self.users:
            return {"success": False, "error": "User not found"}
        self.users[user_id].is_active = False
        return {"success": True, "message": "Account deactivated"}

    def validate_session(self, session_token: str) -> Optional[str]:
        session = self.sessions.get(session_token)
        if not session:
            return None
        if datetime.fromisoformat(session["expires_at"]) < datetime.utcnow():
            del self.sessions[session_token]
            return None
        return session["user_id"]


