class VirtualTourModule:
    """Manages virtual tours of cultural landmarks and historical sites."""

    def __init__(self, user_system: UserRegistrationSystem):
        self.user_system = user_system
        self.tours: dict = {}
        self.user_progress: dict = {}
        self.bookmarks: dict = {}

    def create_tour(self, creator_id: str, title: str, description: str,
                    country: str, region: str = "", category: str = "",
                    tags: list = None) -> dict:
        user = self.user_system.get_user(creator_id)
        if not user:
            return {"success": False, "error": "User not found"}

        tour_id = str(uuid.uuid4())
        tour = VirtualTour(
            tour_id=tour_id,
            title=title,
            description=description,
            country=country,
            region=region,
            category=category,
            created_by=creator_id,
            tags=tags or []
        )
        self.tours[tour_id] = tour

        return {"success": True, "tour_id": tour_id}

    def add_scene(self, tour_id: str, name: str, description: str,
                  model_url: str, thumbnail_url: str = "", order: int = 0) -> dict:
        if tour_id not in self.tours:
            return {"success": False, "error": "Tour not found"}

        scene_id = str(uuid.uuid4())
        scene = Scene(
            scene_id=scene_id,
            name=name,
            description=description,
            model_url=model_url,
            thumbnail_url=thumbnail_url,
            order=order
        )
        self.tours[tour_id].scenes.append(scene)

        return {"success": True, "scene_id": scene_id}

    def add_hotspot(self, tour_id: str, scene_id: str, name: str,
                    hotspot_type: str, position: dict,
                    content: str = "", media_url: str = "") -> dict:
        tour = self.tours.get(tour_id)
        if not tour:
            return {"success": False, "error": "Tour not found"}

        scene = next((s for s in tour.scenes if s.scene_id == scene_id), None)
        if not scene:
            return {"success": False, "error": "Scene not found"}

        hotspot_id = str(uuid.uuid4())
        hotspot = Hotspot(
            hotspot_id=hotspot_id,
            name=name,
            hotspot_type=HotspotType(hotspot_type),
            position=position,
            content=content,
            media_url=media_url
        )
        scene.hotspots.append(hotspot)

        return {"success": True, "hotspot_id": hotspot_id}

    def add_audio_guide(self, tour_id: str, scene_id: str, title: str,
                        language: str, audio_url: str, transcript: str = "",
                        duration_seconds: int = 0, narrator: str = "") -> dict:
        tour = self.tours.get(tour_id)
        if not tour:
            return {"success": False, "error": "Tour not found"}

        scene = next((s for s in tour.scenes if s.scene_id == scene_id), None)
        if not scene:
            return {"success": False, "error": "Scene not found"}

        guide_id = str(uuid.uuid4())
        guide = AudioGuide(
            guide_id=guide_id,
            title=title,
            language=language,
            audio_url=audio_url,
            transcript=transcript,
            duration_seconds=duration_seconds,
            narrator=narrator
        )
        scene.audio_guides.append(guide)

        return {"success": True, "guide_id": guide_id}

    def publish_tour(self, tour_id: str, user_id: str) -> dict:
        tour = self.tours.get(tour_id)
        if not tour:
            return {"success": False, "error": "Tour not found"}
        if tour.created_by != user_id:
            return {"success": False, "error": "Only the creator can publish"}
        if not tour.scenes:
            return {"success": False, "error": "Tour must have at least one scene"}

        tour.is_published = True
        return {"success": True, "message": "Tour published"}

    def get_tour(self, tour_id: str) -> Optional[VirtualTour]:
        return self.tours.get(tour_id)

    def explore_tour(self, user_id: str, tour_id: str) -> dict:
        tour = self.tours.get(tour_id)
        if not tour:
            return {"success": False, "error": "Tour not found"}
        if not tour.is_published:
            return {"success": False, "error": "Tour is not published"}

        tour.visitor_count += 1

        progress_key = f"{user_id}:{tour_id}"
        if progress_key not in self.user_progress:
            self.user_progress[progress_key] = {
                "started_at": datetime.utcnow().isoformat(),
                "scenes_visited": [],
                "hotspots_clicked": [],
                "completed": False
            }

        return {
            "success": True,
            "tour": {
                "title": tour.title,
                "description": tour.description,
                "scenes_count": len(tour.scenes),
                "country": tour.country
            }
        }

    def visit_scene(self, user_id: str, tour_id: str, scene_id: str) -> dict:
        tour = self.tours.get(tour_id)
        if not tour:
            return {"success": False, "error": "Tour not found"}

        scene = next((s for s in tour.scenes if s.scene_id == scene_id), None)
        if not scene:
            return {"success": False, "error": "Scene not found"}

        progress_key = f"{user_id}:{tour_id}"
        if progress_key in self.user_progress:
            if scene_id not in self.user_progress[progress_key]["scenes_visited"]:
                self.user_progress[progress_key]["scenes_visited"].append(scene_id)

            total_scenes = len(tour.scenes)
            visited = len(self.user_progress[progress_key]["scenes_visited"])
            if visited >= total_scenes:
                self.user_progress[progress_key]["completed"] = True

        return {
            "success": True,
            "scene": {
                "name": scene.name,
                "description": scene.description,
                "model_url": scene.model_url,
                "hotspots": [
                    {"id": h.hotspot_id, "name": h.name, "type": h.hotspot_type.value,
                     "position": h.position}
                    for h in scene.hotspots
                ],
                "audio_guides": [
                    {"id": g.guide_id, "title": g.title, "language": g.language}
                    for g in scene.audio_guides
                ]
            }
        }

    def click_hotspot(self, user_id: str, tour_id: str, scene_id: str,
                      hotspot_id: str) -> dict:
        tour = self.tours.get(tour_id)
        if not tour:
            return {"success": False, "error": "Tour not found"}

        scene = next((s for s in tour.scenes if s.scene_id == scene_id), None)
        if not scene:
            return {"success": False, "error": "Scene not found"}

        hotspot = next((h for h in scene.hotspots if h.hotspot_id == hotspot_id), None)
        if not hotspot:
            return {"success": False, "error": "Hotspot not found"}

        progress_key = f"{user_id}:{tour_id}"
        if progress_key in self.user_progress:
            if hotspot_id not in self.user_progress[progress_key]["hotspots_clicked"]:
                self.user_progress[progress_key]["hotspots_clicked"].append(hotspot_id)

        return {
            "success": True,
            "hotspot": {
                "name": hotspot.name,
                "type": hotspot.hotspot_type.value,
                "content": hotspot.content,
                "media_url": hotspot.media_url
            }
        }

    def search_tours(self, query: str = "", country: str = "",
                     category: str = "", tag: str = "") -> list:
        results = []
        for tour in self.tours.values():
            if not tour.is_published:
                continue
            if query and query.lower() not in tour.title.lower() \
                    and query.lower() not in tour.description.lower():
                continue
            if country and country.lower() != tour.country.lower():
                continue
            if category and category.lower() != tour.category.lower():
                continue
            if tag and tag.lower() not in [t.lower() for t in tour.tags]:
                continue
            results.append(tour)
        return results

    def bookmark_tour(self, user_id: str, tour_id: str) -> dict:
        if tour_id not in self.tours:
            return {"success": False, "error": "Tour not found"}
        if user_id not in self.bookmarks:
            self.bookmarks[user_id] = []
        if tour_id not in self.bookmarks[user_id]:
            self.bookmarks[user_id].append(tour_id)
        return {"success": True, "message": "Tour bookmarked"}

    def get_user_bookmarks(self, user_id: str) -> list:
        tour_ids = self.bookmarks.get(user_id, [])
        return [self.tours[tid] for tid in tour_ids if tid in self.tours]


