class TranslationTool:
    """Simulated translation service for language exchange assistance."""

    SUPPORTED_LANGUAGES = [
        "english", "spanish", "french", "german", "italian",
        "portuguese", "chinese", "japanese", "korean", "arabic",
        "hindi", "russian", "dutch", "swedish", "turkish"
    ]

    def translate(self, text: str, source_lang: str, target_lang: str) -> TranslationResult:
        source = source_lang.lower()
        target = target_lang.lower()

        if source not in self.SUPPORTED_LANGUAGES:
            raise ValueError(f"Unsupported source language: {source_lang}")
        if target not in self.SUPPORTED_LANGUAGES:
            raise ValueError(f"Unsupported target language: {target_lang}")

        translated = f"[{target_lang}] {text}"

        return TranslationResult(
            original_text=text,
            translated_text=translated,
            source_language=source_lang,
            target_language=target_lang,
            confidence=0.92
        )

    def detect_language(self, text: str) -> dict:
        return {
            "detected_language": "english",
            "confidence": 0.95
        }

    def get_supported_languages(self) -> list:
        return self.SUPPORTED_LANGUAGES.copy()


class LanguageLearningModule:
    """Facilitates real-time language exchanges between paired users."""

    def __init__(self, user_system: UserRegistrationSystem,
                 tour_module: VirtualTourModule):
        self.user_system = user_system
        self.tour_module = tour_module
        self.translator = TranslationTool()
        self.language_profiles: dict = {}
        self.exchange_sessions: dict = {}
        self.matching_queue: list = []

    def create_language_profile(self, user_id: str, native_languages: list,
                                learning_languages: list,
                                proficiency_levels: dict = None,
                                preferred_topics: list = None) -> dict:
        user = self.user_system.get_user(user_id)
        if not user:
            return {"success": False, "error": "User not found"}

        profile = LanguageProfile(
            user_id=user_id,
            native_languages=native_languages,
            learning_languages=learning_languages,
            proficiency_levels=proficiency_levels or {},
            preferred_topics=preferred_topics or []
        )
        self.language_profiles[user_id] = profile

        return {"success": True, "message": "Language profile created"}

    def update_language_profile(self, user_id: str, **kwargs) -> dict:
        if user_id not in self.language_profiles:
            return {"success": False, "error": "Language profile not found"}

        profile = self.language_profiles[user_id]
        for key, value in kwargs.items():
            if hasattr(profile, key):
                setattr(profile, key, value)

        return {"success": True, "message": "Language profile updated"}

    def find_language_partner(self, user_id: str, target_language: str) -> dict:
        if user_id not in self.language_profiles:
            return {"success": False, "error": "Create a language profile first"}

        user_profile = self.language_profiles[user_id]
        candidates = []

        for pid, profile in self.language_profiles.items():
            if pid == user_id:
                continue
            if target_language.lower() in [l.lower() for l in profile.native_languages]:
                user_native = [l.lower() for l in user_profile.native_languages]
                partner_learning = [l.lower() for l in profile.learning_languages]
                mutual_benefit = any(l in user_native for l in partner_learning)
                candidates.append({
                    "user_id": pid,
                    "mutual_benefit": mutual_benefit,
                    "native_languages": profile.native_languages,
                    "learning_languages": profile.learning_languages
                })

        candidates.sort(key=lambda x: x["mutual_benefit"], reverse=True)
        return {"success": True, "partners": candidates[:10]}

    def request_exchange_session(self, requester_id: str, partner_id: str,
                                 language_to_practice: str,
                                 duration_minutes: int = 30) -> dict:
        if requester_id not in self.language_profiles:
            return {"success": False, "error": "Requester has no language profile"}
        if partner_id not in self.language_profiles:
            return {"success": False, "error": "Partner has no language profile"}

        partner_profile = self.language_profiles[partner_id]
        native_langs = [l.lower() for l in partner_profile.native_languages]
        if language_to_practice.lower() not in native_langs:
            return {"success": False,
                    "error": "Partner is not a native speaker of the requested language"}

        session_id = str(uuid.uuid4())
        requester_profile = self.language_profiles[requester_id]
        language_taught = ""
        for lang in requester_profile.native_languages:
            if lang.lower() in [l.lower() for l in partner_profile.learning_languages]:
                language_taught = lang
                break

        session = LanguageExchangeSession(
            session_id=session_id,
            user1_id=requester_id,
            user2_id=partner_id,
            language_taught=language_taught,
            language_learned=language_to_practice,
            duration_minutes=duration_minutes
        )
        self.exchange_sessions[session_id] = session

        return {"success": True, "session_id": session_id}

    def start_exchange_session(self, session_id: str, user_id: str) -> dict:
        session = self.exchange_sessions.get(session_id)
        if not session:
            return {"success": False, "error": "Session not found"}
        if user_id not in (session.user1_id, session.user2_id):
            return {"success": False, "error": "User not part of this session"}
        if session.status != SessionStatus.WAITING:
            return {"success": False, "error": "Session cannot be started"}

        session.status = SessionStatus.ACTIVE
        session.started_at = datetime.utcnow().isoformat()

        return {"success": True, "message": "Session started"}

    def send_message(self, session_id: str, sender_id: str,
                     content: str, auto_translate: bool = True) -> dict:
        session = self.exchange_sessions.get(session_id)
        if not session:
            return {"success": False, "error": "Session not found"}
        if session.status != SessionStatus.ACTIVE:
            return {"success": False, "error": "Session is not active"}
        if sender_id not in (session.user1_id, session.user2_id):
            return {"success": False, "error": "User not part of this session"}

        message_id = str(uuid.uuid4())
        translation = None

        if auto_translate:
            if sender_id == session.user1_id:
                target_lang = session.language_learned
            else:
                target_lang = session.language_taught or "english"

            try:
                detected = self.translator.detect_language(content)
                source_lang = detected["detected_language"]
                if source_lang.lower() != target_lang.lower():
                    translation = self.translator.translate(
                        content, source_lang, target_lang
                    )
            except ValueError:
                pass

        message = Message(
            message_id=message_id,
            sender_id=sender_id,
            content=content,
            translation=translation
        )
        session.messages.append(message)

        return {
            "success": True,
            "message_id": message_id,
            "translation": translation.translated_text if translation else None
        }

    def provide_correction(self, session_id: str, message_id: str,
                           corrector_id: str, correction: str) -> dict:
        session = self.exchange_sessions.get(session_id)
        if not session:
            return {"success": False, "error": "Session not found"}
        if corrector_id not in (session.user1_id, session.user2_id):
            return {"success": False, "error": "User not part of this session"}

        message = next(
            (m for m in session.messages if m.message_id == message_id), None
        )
        if not message:
            return {"success": False, "error": "Message not found"}

        message.is_corrected = True
        message.correction = correction

        return {"success": True, "message": "Correction provided"}

    def end_exchange_session(self, session_id: str, user_id: str) -> dict:
        session = self.exchange_sessions.get(session_id)
        if not session:
            return {"success": False, "error": "Session not found"}
        if user_id not in (session.user1_id, session.user2_id):
            return {"success": False, "error": "User not part of this session"}

        session.status = SessionStatus.COMPLETED
        session.ended_at = datetime.utcnow().isoformat()

        for uid in (session.user1_id, session.user2_id):
            if uid in self.language_profiles:
                self.language_profiles[uid].total_sessions += 1
                self.language_profiles[uid].total_hours += (
                    session.duration_minutes / 60.0
                )

        return {"success": True, "message": "Session completed"}

    def translate_text(self, text: str, source_lang: str,
                       target_lang: str) -> dict:
        try:
            result = self.translator.translate(text, source_lang, target_lang)
            return {
                "success": True,
                "translation": result.translated_text,
                "confidence": result.confidence
            }
        except ValueError as e:
            return {"success": False, "error": str(e)}

    def get_session_history(self, user_id: str) -> list:
        sessions = []
        for session in self.exchange_sessions.values():
            if user_id in (session.user1_id, session.user2_id):
                sessions.append(session)
        return sessions


