class CulturalWorkshopModule:
    """Hosts live and pre-recorded cultural workshops led by experts."""

    def __init__(self, user_system: UserRegistrationSystem,
                 language_module: LanguageLearningModule):
        self.user_system = user_system
        self.language_module = language_module
        self.workshops: dict = {}
        self.expert_profiles: dict = {}

    def register_expert(self, user_id: str, expertise_areas: list,
                        credentials: str = "", bio: str = "") -> dict:
        user = self.user_system.get_user(user_id)
        if not user:
            return {"success": False, "error": "User not found"}

        self.expert_profiles[user_id] = {
            "user_id": user_id,
            "expertise_areas": expertise_areas,
            "credentials": credentials,
            "bio": bio,
            "workshops_hosted": 0,
            "registered_at": datetime.utcnow().isoformat()
        }
        user.role = UserRole.EXPERT

        return {"success": True, "message": "Expert profile created"}

    def create_workshop(self, host_id: str, title: str, description: str,
                        workshop_type: str, category: str = "",
                        country: str = "", scheduled_at: str = "",
                        duration_minutes: int = 60,
                        max_participants: int = 50,
                        tags: list = None, is_free: bool = True) -> dict:
        if host_id not in self.expert_profiles:
            return {"success": False, "error": "Only registered experts can host workshops"}

        workshop_id = str(uuid.uuid4())
        workshop = Workshop(
            workshop_id=workshop_id,
            title=title,
            description=description,
            workshop_type=WorkshopType(workshop_type),
            host_id=host_id,
            category=category,
            country=country,
            scheduled_at=scheduled_at,
            duration_minutes=duration_minutes,
            max_participants=max_participants,
            tags=tags or [],
            is_free=is_free
        )
        self.workshops[workshop_id] = workshop

        return {"success": True, "workshop_id": workshop_id}

    def schedule_workshop(self, workshop_id: str, scheduled_at: str) -> dict:
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}

        workshop.scheduled_at = scheduled_at
        workshop.status = WorkshopStatus.SCHEDULED

        return {"success": True, "message": "Workshop scheduled"}

    def join_workshop(self, workshop_id: str, user_id: str) -> dict:
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}

        user = self.user_system.get_user(user_id)
        if not user:
            return {"success": False, "error": "User not found"}

        if workshop.status == WorkshopStatus.CANCELLED:
            return {"success": False, "error": "Workshop has been cancelled"}

        if len(workshop.participants) >= workshop.max_participants:
            return {"success": False, "error": "Workshop is full"}

        if user_id in workshop.participants:
            return {"success": False, "error": "Already joined this workshop"}

        workshop.participants.append(user_id)

        return {"success": True, "message": "Joined workshop successfully"}

    def leave_workshop(self, workshop_id: str, user_id: str) -> dict:
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}

        if user_id not in workshop.participants:
            return {"success": False, "error": "User not in this workshop"}

        workshop.participants.remove(user_id)

        return {"success": True, "message": "Left workshop"}

    def start_workshop(self, workshop_id: str, host_id: str) -> dict:
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}
        if workshop.host_id != host_id:
            return {"success": False, "error": "Only the host can start the workshop"}
        if workshop.status not in (WorkshopStatus.SCHEDULED, WorkshopStatus.DRAFT):
            return {"success": False, "error": "Workshop cannot be started"}

        workshop.status = WorkshopStatus.LIVE

        return {"success": True, "message": "Workshop is now live"}

    def end_workshop(self, workshop_id: str, host_id: str,
                     recording_url: str = "") -> dict:
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}
        if workshop.host_id != host_id:
            return {"success": False, "error": "Only the host can end the workshop"}

        workshop.status = WorkshopStatus.COMPLETED
        if recording_url:
            workshop.recording_url = recording_url

        if host_id in self.expert_profiles:
            self.expert_profiles[host_id]["workshops_hosted"] += 1

        return {"success": True, "message": "Workshop completed"}

    def ask_question(self, workshop_id: str, user_id: str,
                     content: str) -> dict:
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}
        if user_id not in workshop.participants and user_id != workshop.host_id:
            return {"success": False, "error": "Must be a participant to ask questions"}

        question_id = str(uuid.uuid4())
        question = WorkshopQuestion(
            question_id=question_id,
            user_id=user_id,
            content=content
        )
        workshop.questions.append(question)

        return {"success": True, "question_id": question_id}

    def answer_question(self, workshop_id: str, question_id: str,
                        answerer_id: str, answer: str) -> dict:
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}

        question = next(
            (q for q in workshop.questions if q.question_id == question_id), None
        )
        if not question:
            return {"success": False, "error": "Question not found"}

        question.answer = answer
        question.answered_by = answerer_id
        question.is_answered = True

        return {"success": True, "message": "Question answered"}

    def post_discussion(self, workshop_id: str, user_id: str,
                        content: str) -> dict:
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}
        if user_id not in workshop.participants and user_id != workshop.host_id:
            return {"success": False, "error": "Must be a participant to post"}

        post_id = str(uuid.uuid4())
        post = DiscussionPost(
            post_id=post_id,
            user_id=user_id,
            content=content
        )
        workshop.discussion.append(post)

        return {"success": True, "post_id": post_id}

    def reply_to_post(self, workshop_id: str, post_id: str,
                      user_id: str, content: str) -> dict:
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}

        post = next(
            (p for p in workshop.discussion if p.post_id == post_id), None
        )
        if not post:
            return {"success": False, "error": "Post not found"}

        reply_id = str(uuid.uuid4())
        reply = DiscussionPost(
            post_id=reply_id,
            user_id=user_id,
            content=content
        )
        post.replies.append(reply)

        return {"success": True, "reply_id": reply_id}

    def upload_material(self, workshop_id: str, host_id: str,
                        title: str, file_url: str,
                        material_type: str = "document") -> dict:
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}
        if workshop.host_id != host_id:
            return {"success": False, "error": "Only the host can upload materials"}

        material = {
            "id": str(uuid.uuid4()),
            "title": title,
            "file_url": file_url,
            "type": material_type,
            "uploaded_at": datetime.utcnow().isoformat()
        }
        workshop.materials.append(material)

        return {"success": True, "material_id": material["id"]}

    def search_workshops(self, query: str = "", category: str = "",
                         country: str = "", workshop_type: str = "",
                         status: str = "") -> list:
        results = []
        for workshop in self.workshops.values():
            if query:
                if query.lower() not in workshop.title.lower() \
                        and query.lower() not in workshop.description.lower():
                    continue
            if category and category.lower() != workshop.category.lower():
                continue
            if country and country.lower() != workshop.country.lower():
                continue
            if workshop_type:
                if workshop.workshop_type.value != workshop_type.lower():
                    continue
            if status and workshop.status.value != status.lower():
                continue
            results.append(workshop)
        return results

    def get_upcoming_workshops(self) -> list:
        now = datetime.utcnow().isoformat()
        upcoming = []
        for workshop in self.workshops.values():
            if workshop.status == WorkshopStatus.SCHEDULED:
                if workshop.scheduled_at >= now:
                    upcoming.append(workshop)
        upcoming.sort(key=lambda w: w.scheduled_at)
        return upcoming


