class CulturalExchangeHub:
    """
    Main platform class that integrates all modules in dependency order:
    1. User Registration System (foundation)
    2. Virtual Tour Module (requires user system)
    3. Language Learning Module (requires tour module)
    4. Cultural Workshop Module (requires language module)
    5. Feedback and Rating System (requires all modules)
    """

    def __init__(self):
        # Step 1: User Registration System (foundation)
        self.user_system = UserRegistrationSystem()

        # Step 2: Virtual Tour Module (depends on user system)
        self.tour_module = VirtualTourModule(self.user_system)

        # Step 3: Language Learning Module (depends on tour module)
        self.language_module = LanguageLearningModule(
            self.user_system, self.tour_module
        )

        # Step 4: Cultural Workshop Module (depends on language module)
        self.workshop_module = CulturalWorkshopModule(
            self.user_system, self.language_module
        )

        # Step 5: Feedback and Rating System (depends on all modules)
        self.feedback_system = FeedbackAndRatingSystem(
            self.user_system, self.tour_module,
            self.language_module, self.workshop_module
        )

    def get_platform_stats(self) -> dict:
        return {
            "total_users": len(self.user_system.users),
            "active_users": sum(
                1 for u in self.user_system.users.values() if u.is_active
            ),
            "total_tours": len(self.tour_module.tours),
            "published_tours": sum(
                1 for t in self.tour_module.tours.values() if t.is_published
            ),
            "total_language_sessions": len(
                self.language_module.exchange_sessions
            ),
            "active_language_sessions": sum(
                1 for s in self.language_module.exchange_sessions.values()
                if s.status == SessionStatus.ACTIVE
            ),
            "total_workshops": len(self.workshop_module.workshops),
            "total_reviews": len(self.feedback_system.reviews),
            "feedback_stats": self.feedback_system.get_platform_statistics()
        }


